values.content:
You are analyzing a grant RFP to identify required sections and questions.

GRANT INFORMATION:
Title: {{ $json.grant_title }}
Funder: {{ $json.funder_name }}
Deadline: {{ $json.deadline }}
Amount: {{ $json.amount }}

BUDGET GENERATED:
{{ $json.budget.narrative }}

---

Based on this grant opportunity, identify the typical sections and questions required for a proposal to this funder.

Return a JSON array of questions in this format:
[
  {
    "question_id": 1,
    "question_text": "Describe your organization's mission and history",
    "word_limit": 500,
    "section_type": "mission",
    "narrative_match": "mission_long",
    "required_docs": ["501c3_letter"]
  }
]

If you don't have specific RFP text, generate standard grant proposal sections based on the funder type (government, foundation, corporate).

parameters.jsCode:
// Parse RFP analysis and prepare for processing
const mergedDataItems = $('Merge Budget Data').all();
const aiResponse = $input.first().json;

// Get the first merged data item
const mergedData = mergedDataItems[0]?.json || {};

let questions = [];
try {
  const responseText = aiResponse.message?.content || aiResponse.text || '';
  const jsonMatch = responseText.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    questions = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  questions = [{
    question_id: 1,
    question_text: 'Describe your organization and program',
    word_limit: 500,
    section_type: 'mission',
    narrative_match: 'mission_long',
    required_docs: ['501c3_letter']
  }];
}

const narrativesNeeded = [...new Set(questions.map(q => q.narrative_match).filter(n => n))];
const docsNeeded = [...new Set(questions.flatMap(q => q.required_docs || []).filter(d => d !== 'none'))];

return [{
  json: {
    grantId: mergedData.grantId  || '',           // ← Now accessing object property
    funderName: mergedData.funder_name || '',
    funderFocus: mergedData.funder_focus || '',
    deadline: mergedData.deadline,
    rfpText: mergedData.rfp_text || '',
    planeIssueId: mergedData.grantId,
    questions: questions,
    narrativesNeeded: narrativesNeeded,
    docsNeeded: docsNeeded,
    totalQuestions: questions.length,
    budget: {
      generated: mergedData.budget?.generated || false,
      amount: mergedData.budget?.amount || 0,
      markdown: mergedData.budget?.markdown || '',
      narrative: mergedData.budget?.narrative || '',
      lineItems: mergedData.budget?.line_items || [],
      categoryTotals: mergedData.budget?.category_totals || {},
      adminPercent: mergedData.budget?.admin_percent || 0,
      warnings: mergedData.budget?.warnings || []
    }
  }
}];

const requirements = $('Step 2: Parse Requirements').first().json;
  const narratives = $('Step 3: Get Narratives').first().json;
  const documents = $input.first().json;

  const questionsWithContent = requirements.questions.map(q => {
    const narrativeContent = narratives.narratives.error_no_match.content;
    const docLinks = [];
    if (q.required_docs && documents.documents) {
      for (const docType of q.required_docs) {
        if (documents.documents[docType] && documents.documents[docType].found) {
          docLinks.push({
            type: docType,
            fileName: documents.documents[docType].fileName,
            link: documents.documents[docType].driveLink
          });
        }
      }
    }

    return {
      ...q,
      narrativeContent: narrativeContent,
      documentLinks: docLinks
    };
  });

  return [{
    json: {
      grantId: requirements.grantId,
      funderName: requirements.funderName,
      funderFocus: requirements.funderFocus,
      deadline: requirements.deadline,
      rfpText: requirements.rfpText,
      planeIssueId: requirements.planeIssueId,
      questions: questionsWithContent,
      missingNarratives: narratives.missingSections || [],
      missingDocs: documents.missingDocs || [],
      // ✅ ADD THIS LINE - Pass through budget data
      budget: requirements.budget || {}
    }
  }];

