parameters.jsCode:
const rawContent = $input.all()[0].json.message.content;
const funder = $('Step 8: Compliance Review').first().json.funder;
const deadline = $('Step 8: Compliance Review').first().json.deadline;
const focus = $('Step 8: Compliance Review').first().json.focus;
const alignmentScore = $('Step 8: Compliance Review').first().json.alignmentScore;
const complianceScore = $('Step 8: Compliance Review').first().json.complianceScore;
const warnings = $('Step 8: Compliance Review').first().json.warnings;

const grantData =
  $('Fetch Eligible Grants').isExecuted
    ? $('Fetch Eligible Grants').first().json
    : $('Fetch Eligible Grants2').isExecuted
      ? $('Fetch Eligible Grants2').first().json
      : {};const id = grantData.id;
const org_id = grantData.org_id;

// Parse AI response
let proposal;
try {
  proposal = JSON.parse(rawContent).grant_proposal;
} catch (e) {
  throw new Error("Failed to parse AI response JSON: " + e.message);
}

// Helper to extract markdown tables
function extractTable(text) {
  const lines = text.split('\n');
  const tableLines = [];
  const remainingLines = [];

  lines.forEach(line => {
    if (line.includes('|')) tableLines.push(line);
    else remainingLines.push(line);
  });

  return {
    content: remainingLines.join('\n').trim() || null,
    tabulation: tableLines.length ? tableLines.join('\n') : null
  };
}

const sections = [];
let sectionIndex = 1;

// =============================
// 1️⃣ TOP TITLE META SECTION
// =============================
sections.push({
  title: funder + ' Proposal',
  header1: null,
  header2: null,
  content: [
    { chapter: 'Funder: ' + funder, sort_order: 1 },
    { chapter: 'Deadline: ' + deadline, sort_order: 2 },
    { chapter: 'Focus: ' + focus, sort_order: 3 },
  ],
  tabulation: null,
  sort_order: sectionIndex++,
});

// =============================
// 2️⃣ BUILD ACTUAL PROPOSAL SECTIONS FIRST (store separately)
// =============================
const proposalSections = [];
const tocChapters = [];

let tocIndex = 1;

for (const [sectionKey, sectionContent] of Object.entries(proposal.sections)) {

  let sortOrder = 1;
  const header1Arr = [];
  const header2Arr = [];
  const contentArr = [];
  const tabulationArr = [];

  const sectionTitle = sectionKey
    .replace(/^\d+_/, '')
    .replace(/_/g, ' ')
    .replace(/\b\w/g, l => l.toUpperCase());

  // Add to TOC (numbered dynamically)
  tocChapters.push({
    chapter: `${tocIndex}. ${sectionTitle}`,
    sort_order: tocIndex
  });

  tocIndex++;

  const { content: mainContent, tabulation } = extractTable(sectionContent);

  if (mainContent) {
    mainContent.split('\n').forEach(line => {
      const trimmed = line.trim();
      if (!trimmed) return;

      if (/:$/.test(trimmed)) {
        header2Arr.push({ chapter: trimmed, sort_order: sortOrder++ });
      } else {
        contentArr.push({ chapter: trimmed, sort_order: sortOrder++ });
      }
    });
  }

  if (tabulation) {
    tabulationArr.push({ chapter: tabulation, sort_order: sortOrder++ });
  }

  proposalSections.push({
    title: sectionTitle,
    header1: header1Arr.length ? header1Arr : null,
    header2: header2Arr.length ? header2Arr : null,
    content: contentArr.length ? contentArr : null,
    tabulation: tabulationArr.length ? tabulationArr : null,
  });
}

// =============================
// 3️⃣ INSERT TABLE OF CONTENTS
// =============================
sections.push({
  title: 'Table of Contents',
  header1: null,
  header2: null,
  content: tocChapters,
  tabulation: null,
  sort_order: sectionIndex++,
});

// =============================
// 4️⃣ APPEND REAL SECTIONS
// =============================
proposalSections.forEach(sec => {
  sections.push({
    ...sec,
    sort_order: sectionIndex++,
  });
});

// =============================
// FINAL RETURN
// =============================
return [{
  json: {
    proposalData: {
      org_id: org_id,
      grant_id: id,
      title: funder + ' Proposal',
      status: 'draft',
      sections: sections,
    },
    proposalMarkdown: rawContent,
    funder: funder,
    deadline: deadline,
    focus: focus,
    alignmentScore: alignmentScore,
    complianceScore: complianceScore,
    warnings: warnings,
  }
}];
